SELECT 
FROM "conversation"
WHERE "conversation_id" = #{conversationId}
  AND "creator_id" = #{userId}
  AND "deleted" = FALSE

SELECT EXISTS (
    SELECT 1
    FROM "conversation"
    WHERE "conversation_id" = #{conversationId}
      AND "creator_id" = #{userId}
      AND "deleted" = FALSE
)

SELECT FROM "conversation" c WHERE c."creator_id" = #{userId} AND c."deleted" = FALSE AND NOT EXISTS ( SELECT 1 FROM "conversation_group_relation" r WHERE r."creator_id" = c."creator_id" AND r."conversation_id" = c."conversation_id" )
AND c."title" ILIKE CONCAT('%', #{keyword}, '%')
ORDER BY c."pinned" DESC, c."modification_time" DESC, c."id" DESC LIMIT #{limit} OFFSET #{offset}

UPDATE "conversation"
SET "title" = #{title},
    "modifier_id" = #{userId}
WHERE "conversation_id" = #{conversationId}
  AND "creator_id" = #{userId}
  AND "deleted" = FALSE
RETURNING

