UPDATE "conversation"
SET "deleted" = TRUE,
    "modifier_id" = #{userId}
WHERE "conversation_id" = #{conversationId}
  AND "creator_id" = #{userId}
  AND "deleted" = FALSE

UPDATE "conversation"
SET "deleted" = TRUE,
    "modifier_id" = #{userId}
WHERE "creator_id" = #{userId}
  AND "deleted" = FALSE
  AND "conversation_id" IN (
      SELECT "conversation_id"
      FROM "conversation_group_relation"
      WHERE "creator_id" = #{userId}
        AND "conversation_group_id" = #{groupId}
  )

